    // ──────────────────────────────────────────────────────────────
    //  Reference tests: compare our output against ONNX Runtime ground truth
    //  Generated by tools/gen_references.py using onnxruntime 1.24.3
    // ──────────────────────────────────────────────────────────────

    /// <summary>Helper: load float32 binary and run inference, return output floats.</summary>
    private async Task<(float[] actual, float[] expected)> RunReferenceComparison(
        Accelerator accelerator, string modelPath, string inputRefPath, string outputRefPath,
        int[] inputShape)
    {
        var http = GetHttpClient();
        if (http == null) throw new UnsupportedTestException("HttpClient not available");

        var inputBytes = await http.GetByteArrayAsync(inputRefPath);
        var inputFloats = new float[inputBytes.Length / 4];
        Buffer.BlockCopy(inputBytes, 0, inputFloats, 0, inputBytes.Length);

        var outputBytes = await http.GetByteArrayAsync(outputRefPath);
        var expected = new float[outputBytes.Length / 4];
        Buffer.BlockCopy(outputBytes, 0, expected, 0, outputBytes.Length);

        var session = await InferenceSession.CreateFromFileAsync(accelerator, http, modelPath);
        using var inputBuf = accelerator.Allocate1D(inputFloats);
        var inputTensor = new Tensor(inputBuf.View, inputShape);

        var outputs = await session.RunAsync(new Dictionary<string, Tensor>
        {
            [session.InputNames[0]] = inputTensor
        });

        var output = outputs[session.OutputNames[0]];
        int elems = output.ElementCount;
        using var readBuf = accelerator.Allocate1D<float>(elems);
        new ElementWiseKernels(accelerator).Scale(output.Data.SubView(0, elems), readBuf.View, elems, 1f);
        await accelerator.SynchronizeAsync();
        var actual = await readBuf.CopyToHostAsync<float>(0, elems);

        session.Dispose();
        return (actual, expected);
    }

    /// <summary>Helper: assert mean error within threshold.</summary>
    private static void AssertReferenceMatch(float[] actual, float[] expected, float maxMeanErr, string name)
    {
        if (actual.Length != expected.Length)
            throw new Exception($"[{name}] Size mismatch: actual={actual.Length}, expected={expected.Length}");

        double sumErr = 0;
        float maxErr = 0;
        for (int i = 0; i < expected.Length; i++)
        {
            float err = MathF.Abs(actual[i] - expected[i]);
            sumErr += err;
            if (err > maxErr) maxErr = err;
        }
        float meanErr = (float)(sumErr / expected.Length);

        if (meanErr > maxMeanErr)
        {
            var a5 = string.Join(",", actual.Take(5).Select(v => v.ToString("F2")));
            var e5 = string.Join(",", expected.Take(5).Select(v => v.ToString("F2")));
            throw new Exception($"[{name}] Mean error {meanErr:F4} > {maxMeanErr}. actual=[{a5}] expected=[{e5}]");
        }
    }

